<script setup lang="ts">
/* eslint vue/singleline-html-element-content-newline: "off", vue/max-attributes-per-line: "off", vue/html-self-closing: "off" */
import { computed, onMounted, reactive, ref, watch } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { AlertCircle, Banknote, CreditCard, FileText, Landmark, Plus, Printer, ReceiptText, Search, Undo2, X } from 'lucide-vue-next'
import InitialsAvatar from '@/components/InitialsAvatar.vue'
import StatePanel from '@/components/StatePanel.vue'
import StatusBadge from '@/components/StatusBadge.vue'
import { ApiError, apiFetch, money, shortDate } from '@/lib/api'
import type { FinanceLedgerItem } from '@/lib/types'
import { useAuthStore } from '@/stores/auth'

interface AccountOption { accountType:'membership'|'course';accountId:string;participantId:string;participantName:string;contextName:string;balanceCents:number }
interface LedgerResponse { items:FinanceLedgerItem[];meta:{total:number};todayCash:{totalCents:number;cashCents:number;cardCents:number;transferCents:number;otherCents:number;voidedCents:number;recordCount:number} }
const route=useRoute();const router=useRouter();const auth=useAuthStore();const data=ref<LedgerResponse|null>(null);const accounts=ref<AccountOption[]>([]);const loading=ref(true);const saving=ref(false);const error=ref('');const open=ref(typeof route.query.enrollmentId==='string');const voidTarget=ref<FinanceLedgerItem|null>(null);const receiptTarget=ref<FinanceLedgerItem|null>(null)
const filters=reactive({query:typeof route.query.query==='string'?route.query.query:'',type:'all',status:'',dateFrom:'',dateTo:''})
const form=reactive({accountKey:'',amount:0,method:'cash',reference:'',note:''});const voidReason=ref('')
const selectedAccount=computed(()=>accounts.value.find((item)=>`${item.accountType}:${item.accountId}`===form.accountKey))
const canVoid=computed(()=>auth.isManager)
const kindLabel:Record<string,string>={membership_payment:'Üyelik tahsilatı',course_payment:'Kurs tahsilatı',additional_charge:'Ek ücret',membership_charge:'Paket bedeli',course_charge:'Kurs ücreti'}
const methodLabel:Record<string,string>={cash:'Nakit',card_terminal:'Kart terminali',bank_transfer:'Havale/EFT',other:'Diğer'}
const canVoidItem=(item:FinanceLedgerItem)=>item.status==='recorded'&&['membership_payment','course_payment','additional_charge'].includes(item.kind)
let debounce:ReturnType<typeof globalThis.setTimeout>

async function load(){loading.value=true;error.value='';const params=new globalThis.URLSearchParams({page:'1',pageSize:'100',type:filters.type});if(filters.query)params.set('query',filters.query);if(filters.status)params.set('status',filters.status);if(filters.dateFrom)params.set('dateFrom',filters.dateFrom);if(filters.dateTo)params.set('dateTo',filters.dateTo);try{data.value=await apiFetch<LedgerResponse>(`/payments?${params}`)}catch(cause){error.value=cause instanceof Error?cause.message:'Finans defteri alınamadı.'}finally{loading.value=false}}
async function loadAccounts(){try{accounts.value=(await apiFetch<{items:AccountOption[]}>('/finance/accounts')).items;const routeEnrollment=typeof route.query.enrollmentId==='string'?route.query.enrollmentId:'';const preferred=accounts.value.find((item)=>item.accountId===routeEnrollment)??accounts.value[0];if(preferred&&!form.accountKey){form.accountKey=`${preferred.accountType}:${preferred.accountId}`;form.amount=preferred.balanceCents/100}}catch(cause){error.value=cause instanceof Error?cause.message:'Açık hesaplar alınamadı.'}}
function selectAccount(){if(selectedAccount.value)form.amount=selectedAccount.value.balanceCents/100}
function openPayment(){open.value=true;error.value='';if(selectedAccount.value)form.amount=selectedAccount.value.balanceCents/100}
async function record(){if(!selectedAccount.value)return;saving.value=true;error.value='';const endpoint=selectedAccount.value.accountType==='membership'?`/memberships/${selectedAccount.value.accountId}/payments`:`/enrollments/${selectedAccount.value.accountId}/payments`;try{await apiFetch(endpoint,{method:'POST',body:JSON.stringify({amountCents:Math.round(Number(form.amount)*100),method:form.method,reference:form.reference||null,note:form.note||null,allowOverpayment:false})});open.value=false;Object.assign(form,{accountKey:'',amount:0,method:'cash',reference:'',note:''});await Promise.all([load(),loadAccounts()])}catch(cause){error.value=cause instanceof ApiError?cause.message:'Tahsilat kaydedilemedi.'}finally{saving.value=false}}
function requestVoid(item:FinanceLedgerItem){voidTarget.value=item;voidReason.value='';error.value=''}
async function voidMovement(){if(!voidTarget.value||voidReason.value.trim().length<3)return;saving.value=true;const endpoint=voidTarget.value.kind==='course_payment'?`/payments/${voidTarget.value.id}/void`:voidTarget.value.kind==='membership_payment'?`/membership-payments/${voidTarget.value.id}/void`:`/membership-charges/${voidTarget.value.id}/void`;try{await apiFetch(endpoint,{method:'POST',body:JSON.stringify({reason:voidReason.value.trim()})});voidTarget.value=null;await Promise.all([load(),loadAccounts()])}catch(cause){error.value=cause instanceof ApiError?cause.message:'Hareket geçersiz kılınamadı.'}finally{saving.value=false}}
function printReceipt(){globalThis.print()}
watch(filters,()=>{globalThis.clearTimeout(debounce);debounce=globalThis.setTimeout(()=>{router.replace({query:{...(filters.query?{query:filters.query}:{})}});load()},300)},{deep:true})
onMounted(()=>Promise.all([load(),loadAccounts()]))
</script>

<template>
  <div class="page-header"><div><p class="eyebrow">Kasa ve muhasebe</p><h1>Finans Defteri</h1><p>Üyelik ve kurs alacaklarını, tahsilatları ve ek ücretleri tek denetlenebilir akışta yönetin.</p></div><button class="button button--primary" @click="openPayment"><Plus :size="17" />Tahsilat Kaydet</button></div>
  <div class="notice"><AlertCircle :size="18" /><span>Bu ekran çevrimiçi ödeme yapmaz; personelin kasada aldığı ödemeleri numaralı muhasebe hareketi olarak kaydeder.</span></div>
  <section v-if="data" class="cash-summary"><div><ReceiptText :size="21" /><span>Bugünkü Toplam</span><strong>{{ money(data.todayCash.totalCents) }}</strong><small>{{ data.todayCash.recordCount }} tahsilat</small></div><div><Banknote :size="21" /><span>Nakit</span><strong>{{ money(data.todayCash.cashCents) }}</strong></div><div><CreditCard :size="21" /><span>Kart</span><strong>{{ money(data.todayCash.cardCents) }}</strong></div><div><Landmark :size="21" /><span>Havale/EFT</span><strong>{{ money(data.todayCash.transferCents) }}</strong></div><div><Undo2 :size="21" /><span>Geçersiz</span><strong>{{ money(data.todayCash.voidedCents) }}</strong></div></section>
  <section class="filters ledger-filters"><label class="field"><span>Üye, paket, kurs veya makbuz</span><div class="search-field"><Search :size="16" /><input v-model="filters.query" placeholder="Ara" /></div></label><label class="field"><span>Hareket</span><select v-model="filters.type"><option value="all">Tümü</option><option value="payments">Tahsilatlar</option><option value="charges">Borçlandırmalar</option></select></label><label class="field"><span>Durum</span><select v-model="filters.status"><option value="">Tümü</option><option value="recorded">Geçerli</option><option value="voided">Geçersiz</option></select></label><label class="field"><span>Başlangıç</span><input v-model="filters.dateFrom" type="date" /></label><label class="field"><span>Bitiş</span><input v-model="filters.dateTo" type="date" /></label></section>
  <StatePanel v-if="loading" state="loading" /><StatePanel v-else-if="error&&!data" state="error" :message="error" @retry="load" /><StatePanel v-else-if="!data?.items.length" state="empty" title="Finans hareketi yok" message="Seçili ölçütlerde hesap hareketi bulunmuyor." />
  <section v-else class="card table-wrap"><table class="data-table ledger-table"><thead><tr><th>Üye</th><th>Kaynak</th><th>Hareket</th><th>Tarih</th><th>Tutar</th><th>Makbuz</th><th>Yöntem</th><th>Personel</th><th>Durum</th><th><span class="sr-only">İşlem</span></th></tr></thead><tbody><tr v-for="item in data.items" :key="`${item.kind}-${item.id}`"><td><RouterLink class="person-cell" :to="`/members/${item.participantId}`"><InitialsAvatar :name="item.participantName" size="sm" /><strong>{{ item.participantName }}</strong></RouterLink></td><td>{{ item.contextName }}</td><td><span class="movement-kind" :class="`movement-kind--${item.direction}`">{{ kindLabel[item.kind] }}</span></td><td>{{ shortDate(item.occurredAt) }}</td><td><strong :class="item.direction==='charge'?'text-danger':'text-success'">{{ item.direction==='charge'?'+':'−' }} {{ money(item.amountCents) }}</strong></td><td><button v-if="item.receiptNumber" class="receipt-link" type="button" @click="receiptTarget=item"><FileText :size="14" />{{ item.receiptNumber }}</button><span v-else class="muted">—</span></td><td>{{ item.method?methodLabel[item.method]:'—' }}</td><td>{{ item.recordedBy }}</td><td><StatusBadge :tone="item.status==='recorded'?'success':'neutral'" :label="item.status==='recorded'?'Geçerli':'Geçersiz'" /><small v-if="item.voidReason" class="void-reason">{{ item.voidReason }}</small></td><td><button v-if="canVoid&&canVoidItem(item)" class="button button--danger button--small" @click="requestVoid(item)">Geçersiz Kıl</button></td></tr></tbody></table></section>

  <div v-if="open" class="modal-backdrop" @click.self="open=false"><form class="modal card" role="dialog" aria-modal="true" aria-labelledby="payment-title" @submit.prevent="record"><div class="card__header"><h2 id="payment-title">Tahsilat Kaydet</h2><button class="icon-button" type="button" aria-label="Kapat" @click="open=false"><X :size="20" /></button></div><div class="card__body form-grid"><label class="field field--full"><span>Üye hesabı</span><select v-model="form.accountKey" required @change="selectAccount"><option value="">Hesap seçin</option><option v-for="account in accounts" :key="`${account.accountType}:${account.accountId}`" :value="`${account.accountType}:${account.accountId}`">{{ account.participantName }} · {{ account.contextName }} · {{ money(account.balanceCents) }} kalan</option></select></label><div v-if="selectedAccount" class="account-preview field--full"><span>{{ selectedAccount.accountType==='membership'?'Üyelik':'Kurs' }}</span><strong>{{ selectedAccount.participantName }}</strong><p>{{ selectedAccount.contextName }} · {{ money(selectedAccount.balanceCents) }} açık bakiye</p></div><label class="field"><span>Tutar (TL)</span><input v-model.number="form.amount" :max="(selectedAccount?.balanceCents??0)/100" min="0.01" step="0.01" required type="number" /></label><label class="field"><span>Yöntem</span><select v-model="form.method"><option value="cash">Nakit</option><option value="card_terminal">Kart terminali</option><option value="bank_transfer">Havale/EFT</option><option value="other">Diğer</option></select></label><label class="field field--full"><span>Referans</span><input v-model.trim="form.reference" placeholder="Dekont veya POS referansı (isteğe bağlı)" /></label><label class="field field--full"><span>Not</span><textarea v-model.trim="form.note" /></label><div v-if="error" class="notice notice--danger field--full">{{ error }}</div></div><footer class="modal-footer"><span><b>{{ money(Math.round(Number(form.amount)*100)) }}</b> tahsilat</span><div><button class="button button--secondary" type="button" @click="open=false">Vazgeç</button><button class="button button--primary" :disabled="saving||!selectedAccount">{{ saving?'Kaydediliyor…':'Tahsilatı Kaydet' }}</button></div></footer></form></div>

  <div v-if="voidTarget" class="modal-backdrop" @click.self="voidTarget=null"><form class="modal modal--small card" role="dialog" aria-modal="true" @submit.prevent="voidMovement"><div class="card__header"><h2>Hareketi Geçersiz Kıl</h2><button class="icon-button" type="button" aria-label="Kapat" @click="voidTarget=null"><X :size="20" /></button></div><div class="card__body stack"><div class="void-summary"><strong>{{ kindLabel[voidTarget.kind] }} · {{ money(voidTarget.amountCents) }}</strong><span>{{ voidTarget.participantName }} · {{ voidTarget.contextName }}</span></div><label class="field"><span>Gerekçe</span><textarea v-model="voidReason" required minlength="3" placeholder="İşlemin neden geçersiz kılındığını yazın" /></label><div v-if="error" class="notice notice--danger">{{ error }}</div></div><footer class="modal-footer"><span>Silinmez; denetim izi korunur.</span><div><button class="button button--secondary" type="button" @click="voidTarget=null">Vazgeç</button><button class="button button--danger" :disabled="saving||voidReason.trim().length<3">Geçersiz Kıl</button></div></footer></form></div>

  <div v-if="receiptTarget" class="modal-backdrop receipt-backdrop" @click.self="receiptTarget=null"><article class="modal modal--small card receipt" role="dialog" aria-modal="true"><div class="card__header receipt-controls"><h2>Makbuz</h2><div><button class="button button--secondary" @click="printReceipt"><Printer :size="16" />Yazdır</button><button class="icon-button" aria-label="Kapat" @click="receiptTarget=null"><X :size="20" /></button></div></div><div class="card__body receipt-body"><p class="eyebrow">Emniyet Spor Salonu</p><h2>{{ receiptTarget.receiptNumber }}</h2><dl><div><dt>Üye</dt><dd>{{ receiptTarget.participantName }}</dd></div><div><dt>İşlem</dt><dd>{{ kindLabel[receiptTarget.kind] }}</dd></div><div><dt>Paket / Kurs</dt><dd>{{ receiptTarget.contextName }}</dd></div><div><dt>Tarih</dt><dd>{{ shortDate(receiptTarget.occurredAt) }}</dd></div><div><dt>Yöntem</dt><dd>{{ receiptTarget.method?methodLabel[receiptTarget.method]:'—' }}</dd></div><div><dt>Tutar</dt><dd>{{ money(receiptTarget.amountCents) }}</dd></div><div><dt>Kaydeden</dt><dd>{{ receiptTarget.recordedBy }}</dd></div></dl><p class="receipt-note">Bu belge personel tarafından girilen tahsilat kaydını gösterir; çevrimiçi ödeme belgesi değildir.</p></div></article></div>
</template>

<style scoped>
.cash-summary{display:grid;grid-template-columns:repeat(5,1fr);gap:12px;margin:16px 0}.cash-summary>div{display:grid;grid-template-columns:auto 1fr;gap:4px 9px;padding:14px;background:white;border:1px solid #d8e2ee;border-left:4px solid #258bb5}.cash-summary svg{grid-row:1/4;color:#258bb5}.cash-summary span{color:#49607c;font-size:10px;text-transform:uppercase}.cash-summary strong{font-size:18px}.cash-summary small{color:#5d6875}.ledger-filters{grid-template-columns:2fr repeat(4,1fr)}.search-field{display:flex;align-items:center;gap:6px;min-height:42px;padding:0 10px;background:white;border:1px solid #8fa3b7}.search-field input{border:0;box-shadow:none;min-height:auto;padding:0}.ledger-table{min-width:1350px}.person-cell{color:inherit}.movement-kind{display:inline-flex;padding:4px 7px;border:1px solid #d8e2ee;background:#f7f9fb;font-size:11px;font-weight:800}.movement-kind--payment{border-color:#9ac8a4;background:#e9f7ec;color:#164b24}.movement-kind--charge{border-color:#e9b7b2;background:#fff0ee;color:#812520}.receipt-link{display:inline-flex;align-items:center;gap:5px;padding:0;border:0;background:transparent;color:#005087;font-size:11px;font-weight:800}.void-reason{display:block;max-width:170px;margin-top:4px;color:#8a3d35}.button--small{padding:6px 8px;font-size:10px}.modal-backdrop{position:fixed;inset:0;z-index:150;display:grid;place-items:center;padding:18px;background:rgba(5,29,47,.52)}.modal{width:min(700px,100%);max-height:calc(100vh - 36px);overflow:auto}.modal--small{width:min(520px,100%)}.modal-footer{display:flex;align-items:center;justify-content:space-between;gap:12px;padding:15px 18px;border-top:1px solid #d8e2ee;background:#f8fbff}.modal-footer>div{display:flex;gap:8px}.modal-footer span{font-size:12px;color:#49607c}.modal-footer b{color:#051d2f}.account-preview{padding:12px;border:1px solid #b0c9e8;background:#edf4ff}.account-preview span,.account-preview strong{display:block}.account-preview span{color:#49607c;font-size:10px;text-transform:uppercase}.account-preview strong{margin-top:4px}.account-preview p{margin:4px 0 0;color:#31506c;font-size:12px}.void-summary{padding:12px;border:1px solid #e9b7b2;background:#fff0ee}.void-summary strong,.void-summary span{display:block}.void-summary span{margin-top:4px;color:#6f4c48;font-size:12px}.receipt-controls>div{display:flex;align-items:center;gap:8px}.receipt-body h2{margin:5px 0 20px;font-size:25px}.receipt-body dl{display:grid;gap:0;margin:0;border:1px solid #d8e2ee}.receipt-body dl div{display:grid;grid-template-columns:130px 1fr;border-bottom:1px solid #d8e2ee}.receipt-body dl div:last-child{border:0}.receipt-body dt,.receipt-body dd{margin:0;padding:9px 11px}.receipt-body dt{background:#edf4ff;color:#49607c;font-size:11px;font-weight:800}.receipt-body dd{font-weight:700}.receipt-note{margin:16px 0 0;color:#5d6875;font-size:11px}@media(max-width:1000px){.cash-summary{grid-template-columns:repeat(2,1fr)}.ledger-filters{grid-template-columns:1fr 1fr}.ledger-filters .field:first-child{grid-column:1/-1}}@media(max-width:560px){.cash-summary,.ledger-filters{grid-template-columns:1fr}.ledger-filters .field:first-child{grid-column:auto}.modal-footer{align-items:stretch;flex-direction:column}.modal-footer>div{display:grid;grid-template-columns:1fr 1fr}}@media print{body *{visibility:hidden}.receipt,.receipt *{visibility:visible}.receipt{position:fixed;inset:0;width:100%;max-height:none;border:0;box-shadow:none}.receipt-controls{display:none}.receipt-backdrop{position:static;background:white;padding:0}}
</style>
